// Format one landed portal enquiry into an internal notification email.
// Body in:  { notifyTo, enquiry: { id, service, name, email, phone, message, business, category, campaign } }
// Body out: { to, subject, html }
// The customer's own email is set as replyTo-style content in the body; the
// email is SENT to notifyTo (the operator's configured address).

const BRAND = { color: "#c8102e" };

const esc = (s) =>
  (s == null ? "" : s.toString())
    .replace(/&/g, "&amp;").replace(/</g, "&lt;")
    .replace(/>/g, "&gt;").replace(/"/g, "&quot;");

const first = $input.first().json;
const body = first.body ?? first;
const to = (body.notifyTo || "").toString().trim();
const e = (body.enquiry && typeof body.enquiry === "object") ? body.enquiry : {};

// Guard: without a destination address there is nothing to send.
if (!to) { return []; }

const svc = esc(e.service || "General enquiry");
const name = esc(e.name || "(not given)");
const email = esc(e.email || "(not given)");
const phone = esc(e.phone || "(not given)");
const business = esc(e.business || "");
const category = esc(e.category || "");
const campaign = esc(e.campaign || "");
const message = esc(e.message || "").replace(/\n/g, "<br>");

const subject = "New enquiry: " + (e.service || "General") + (e.name ? " - " + e.name : "");

function row(label, val) {
  if (!val || val === "(not given)") {
    val = '<span style="color:#9ca3af;">' + (val || "-") + '</span>';
  }
  return '<tr>' +
    '<td style="padding:6px 12px 6px 0;font-size:13px;color:#6b7280;white-space:nowrap;vertical-align:top;">' + label + '</td>' +
    '<td style="padding:6px 0;font-size:14px;color:#111111;">' + val + '</td>' +
  '</tr>';
}

const html =
'<!doctype html><html><head><meta charset="utf-8"></head>' +
'<body style="margin:0;background:#f4f4f5;font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\',Roboto,Helvetica,Arial,sans-serif;">' +
'<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="padding:24px 12px;"><tr><td align="center">' +
'<table role="presentation" width="560" cellpadding="0" cellspacing="0" style="max-width:560px;width:100%;background:#fff;border-radius:12px;overflow:hidden;">' +
'<tr><td style="background:#111;padding:16px 24px;color:#fff;font-size:16px;font-weight:700;">New portal enquiry</td></tr>' +
'<tr><td style="height:3px;background:' + BRAND.color + ';font-size:0;line-height:0;">&nbsp;</td></tr>' +
'<tr><td style="padding:20px 24px;">' +
'<table role="presentation" cellpadding="0" cellspacing="0" width="100%">' +
row("Service", svc) +
row("Name", name) +
row("Email", '<a href="mailto:' + email + '" style="color:' + BRAND.color + ';">' + email + '</a>') +
row("Phone", phone) +
(business ? row("Business", business) : "") +
(category ? row("Category", category) : "") +
(campaign ? row("Campaign", campaign) : "") +
'</table>' +
'<div style="margin-top:16px;padding-top:14px;border-top:1px solid #ececec;">' +
'<div style="font-size:12px;color:#6b7280;text-transform:uppercase;letter-spacing:.08em;margin-bottom:6px;">Message</div>' +
'<div style="font-size:14px;color:#111;line-height:1.6;">' + (message || '<span style="color:#9ca3af;">(no message)</span>') + '</div>' +
'</div>' +
'<div style="margin-top:18px;">' +
'<a href="mailto:' + email + '?subject=' + encodeURIComponent("Re: your APMG Services enquiry") + '" ' +
'style="display:inline-block;background:' + BRAND.color + ';color:#fff;text-decoration:none;font-weight:600;font-size:14px;padding:10px 20px;border-radius:8px;">Reply to customer</a>' +
'</div>' +
'</td></tr>' +
'<tr><td style="background:#fafafa;border-top:1px solid #ececec;padding:14px 24px;font-size:11px;color:#9ca3af;">' +
'APMG Services - automated enquiry notification. Reply directly to the customer at the address above.' +
'</td></tr>' +
'</table></td></tr></table></body></html>';

return [{ json: { to, subject, html } }];
